#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_TAPE 10000
#define MAX_STATES 100

// Transition: (state, read) -> (new_state, write, move)
// move: 1 = right, -1 = left, 0 = stay
typedef struct {
    int new_state;
    char write;
    int move;
} Transition;

typedef struct {
    int num_states;
    char alphabet[10];
    Transition transitions[MAX_STATES][256]; // indexed by state and read symbol
    int start_state;
    int accept_state;
    int reject_state;
} TuringMachine;

int simulate_utm(TuringMachine *tm, char *input, int max_steps) {
    char tape[MAX_TAPE];
    int tape_size = strlen(input);

    // Initialize tape with input
    for (int i = 0; i < tape_size; i++) {
        tape[i] = input[i];
    }

    int head = 0;
    int state = tm->start_state;

    for (int step = 0; step < max_steps && state != -1; step++) {
        // Check accept/reject states
        if (state == tm->accept_state) return 1;  // ACCEPT
        if (state == tm->reject_state) return 0; // REJECT

        char read = (head >= 0 && head < tape_size) ? tape[head] : '_';
        Transition t = tm->transitions[state][(unsigned char)read];

        // Apply transition
        if (t.new_state == -1) break;  // No transition defined
        tape[head] = t.write;
        head += t.move;
        state = t.new_state;

        // Extend tape if needed
        if (head >= tape_size) {
            tape[head] = '_';
            tape_size = head + 1;
        }
    }

    return -1;  // Did not halt within step limit
}

